(function () {
    'use strict';

    // ─── 1. BLOQUEIA MENU DE CONTEXTO ────────────────────────────────────────
    document.addEventListener("contextmenu", e => e.preventDefault());

    // ─── 2. BLOQUEIA ATALHOS DE TECLADO ──────────────────────────────────────
    document.addEventListener("keydown", function (e) {
        const blocked = [
            e.key === "F12",
            e.ctrlKey && e.shiftKey && ["I", "J", "C", "K"].includes(e.key),
            e.ctrlKey && ["u", "s", "p", "a"].includes(e.key.toLowerCase()),
            e.metaKey && e.altKey && e.key === "I", // Mac DevTools
        ];
        if (blocked.some(Boolean)) e.preventDefault();
    });

    // ─── 3. BLOQUEIA SELEÇÃO E ARRASTE ───────────────────────────────────────
    document.addEventListener('selectstart', e => e.preventDefault());
    document.addEventListener('dragstart', e => e.preventDefault());

    // ─── 4. SILENCIA CONSOLE ─────────────────────────────────────────────────
    const _realLog = console.log.bind(console);
    ['log', 'debug', 'info', 'warn', 'error', 'table', 'dir'].forEach(m => {
        console[m] = function () {};
    });

    // ─── 5. FUNÇÃO DE BLOQUEIO DA PÁGINA ─────────────────────────────────────
    function bloquearPagina() {
        document.documentElement.innerHTML =
            '<body style="background:#000;margin:0;display:flex;align-items:center;justify-content:center;height:100vh">' +
            '<h1 style="color:#fff;font-family:sans-serif;text-align:center">⛔ Acesso não autorizado</h1>' +
            '</body>';
        history.pushState(null, '', location.href);
        window.onpopstate = () => history.pushState(null, '', location.href);
    }

    // ─── 6. DETECÇÃO POR console (Image id getter) ───────────────────────────
    // Quando DevTools está aberto, o getter de 'id' é acionado ao logar a imagem
    const elemento = new Image();
    Object.defineProperty(elemento, 'id', {
        get: function () {
            bloquearPagina();
        }
    });

    setInterval(function () {
        _realLog('%c', elemento);
    }, 1000);

    // ─── 7. DETECÇÃO POR debugger CONTÍNUO ───────────────────────────────────
    // Com DevTools aberto na aba Sources, o debugger pausa e o tempo estoura
    (function loopDebugger() {
        const antes = Date.now();
        debugger;
        const depois = Date.now();
        if (depois - antes > 100) {
            bloquearPagina();
        }
        setTimeout(loopDebugger, 1000);
    })();

    // ─── 8. DETECÇÃO AO ABRIR ANTES DA PÁGINA (via performance) ──────────────
    // Se o DevTools já estava aberto quando a página carregou,
    // o tempo de execução do bloco inicial é muito maior que o normal
    (function checarAbertoAntes() {
        const inicio = performance.now();
        debugger;
        const fim = performance.now();
        if (fim - inicio > 200) {
            bloquearPagina();
        }
    })();

})();